<template>
<section>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered modal-xl">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full d-flex">
                        <h5 class="modal-title">{{ $t("History") }}</h5>
                        <button type="button" class="close" @click="Close">
                            <em class="fa fa-times"></em>
                        </button>
                    </div>
                    <div class="tab padding-t_8">
                        <div class="container-fluid tab-style">
                            <div class="tab_container">
                                <ul class="nav nav-tabs all-tabs">
                                    <li class="nav-item" @click="setActiveTab(1)">
                                        <a href="javascript:void(0)" class="nav-link" :class="{ active: activeTab === 1 }">
                                            <span class="tab-no">1</span>
                                            {{ $t('LINE ITEM HISTORY') }}
                                        </a>
                                    </li>
                                    <li class="nav-item" @click="setActiveTab(2)">
                                        <a href="javascript:void(0)" class="nav-link" :class="{ active: activeTab === 2 }">
                                            <span class="tab-no">2</span>
                                            {{ $t('INVOICE HISTORY') }}
                                        </a>
                                    </li>
                                </ul>
                                <div class="tab-content mt-3">
                                    <div class="tab-pane" :class="{ active: activeTab === 1 }">
                                        <section>
                                            <loader :is-visible="isLoading"></loader>
                                            <tg-list :IsShowAction="false" ModuleName="" SubModuleCode="" :LegendArray="[]"
                                                :RenderRowActionMethod="renderActions" v-on:ActionButtonClick="actionButtonClick" :widgets="[]"
                                                IdentityColumn="" :listType="['List']" :ListData="LineItemHistoryData" :HeaderData="Headers"
                                                :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords" :SearchFields="leftSearchFields"
                                                IsSearchFieldsOnTop="true" SearchPosition="top" :ListDataCallBackFunction="FetchData" :showCheckBox="false"
                                                :SortExp="SortExp" :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')"
                                                v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod"
                                                v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:SortdataButtonClick="sortdata">                                                

                                                <template v-slot:slotdata="{ data }">
                                                    <template v-if="data.column.COLUMN_NAME == 'CREATED_ON'"> 
                                                        {{ $options.filters.formatDate(data.row.CREATED_ON) }}
                                                    </template>  
                                                </template>
                                            </tg-list>
                                        </section>
                                    </div>
                                    <div class="tab-pane" :class="{ active: activeTab === 2 }">
                                        <section>
                                            <loader :is-visible="isLoading"></loader>
                                            <tg-list :IsShowAction="false" ModuleName="" SubModuleCode="" :LegendArray="[]"
                                                :RenderRowActionMethod="renderActions" v-on:ActionButtonClick="actionButtonClick" :widgets="[]"
                                                IdentityColumn="" :listType="['List']" :ListData="InvoiceActionHistoryData" :HeaderData="Headers1"
                                                :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords" :SearchFields="leftSearchFields"
                                                IsSearchFieldsOnTop="true" SearchPosition="top" :ListDataCallBackFunction="FetchData" :showCheckBox="false"
                                                :SortExp="SortExp" :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')"
                                                v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod"
                                                v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:SortdataButtonClick="sortdata">

                                                <template v-slot:slotdata="{ data }">
                                                    <template v-if="data.column.COLUMN_NAME == 'DATE'">
                                                        {{ $options.filters.formatDate(data.row.DATE) }}
                                                    </template>  
                                                </template>
                                            </tg-list>
                                        </section>
                                    </div>
                                </div>
                                <div class="col-lg-12 text-right mt-3" style="clear:both;">
                                    <button class="btn btn-danger" @click="Close">
                                        <em class="fa fa-close pr-2"></em>
                                        {{ $t('Close') }}
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</section>
</template>

<script>
import DataService from '../../../services/DataService';
export default {
    props: {
        BillId: {
            type: Number,
            required: true
        }
    },
    data() {
        return {
            isLoading: false,
            noRecords: false,
            activeTab: 1,
            billId: '',
            invoiceUrl: '',
            LineItemHistoryData: [],
            InvoiceActionHistoryData: [],
            Headers: [{
                    "COLUMN_NAME": "TICKET_NUMBER",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Ticket Number',
                    "DISPLAY_ORDER": 1,
                },
                {
                    "COLUMN_NAME": "ACTIVITY_ID",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Activity Id',
                    "DISPLAY_ORDER": 2
                },
                {
                    "COLUMN_NAME": "DATA",
                    "DATA_TYPE": "Date",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Data',
                    "DISPLAY_ORDER": 3,
                },
                {
                    "COLUMN_NAME": "LOG_MESSAGE",
                    "DATA_TYPE": "Date",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Message',
                    "DISPLAY_ORDER": 4,
                },
                {
                    "COLUMN_NAME": "CREATED_ON",
                    "DATA_TYPE": "Date",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Date',
                    "DISPLAY_ORDER": 5,
                },
                {
                    "COLUMN_NAME": "CREATED_BY_NAME",
                    "DATA_TYPE": "Date",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Created By',
                    "DISPLAY_ORDER": 6,
                }
            ],
            Headers1: [{
                    "COLUMN_NAME": "INVOICE_NUMBER",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Invoice Number',
                    "DISPLAY_ORDER": 1,
                },
                {
                    "COLUMN_NAME": "USER",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'User',
                    "DISPLAY_ORDER": 2
                },
                {
                    "COLUMN_NAME": "ACTION",
                    "DATA_TYPE": "Date",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Action',
                    "DISPLAY_ORDER": 3,
                },
                {
                    "COLUMN_NAME": "DATE",
                    "DATA_TYPE": "Date",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Date',
                    "DISPLAY_ORDER": 4,
                }
            ]
        }
    },
    async created() {
        var vm = this;
        vm.billId = vm.BillId;
        vm.setActiveTab(1);
    },
    methods: {
        formatDate: function (value) {
            if (!value) return '';
            return moment(value).format('MMMM Do, YYYY');
        },
        GetLineItemHistoryReport: async function () {
            var vm = this;
            vm.isLoading = true;
            var params = `BillId=${vm.billId}`
            await DataService.GetLineItemHistoryReport(params).then((response) => {
                if (response.data && response.data.length > 0) {
                    vm.isLoading = false;
                    vm.LineItemHistoryData = response.data;
                    vm.noRecords = false;
                } else {
                    vm.LineItemHistoryData = [];
                    vm.noRecords = true;
                    vm.isLoading = false;
                }
            })
        },
        GetInvoiceActionHistoryReport: async function () {
            var vm = this;
            vm.isLoading = true;
            var params = `BillId=${vm.billId}`
            await DataService.GetInvoiceActionHistoryReport(params).then((response) => {
                if (response.data && response.data.length > 0) {
                    vm.isLoading = false;
                    vm.InvoiceActionHistoryData = response.data;
                    vm.noRecords = false;
                } else {
                    vm.InvoiceActionHistoryData = [];
                    vm.noRecords = true;
                    vm.isLoading = false;
                }
            })
        },
        setActiveTab(tab) {
            var vm = this;
            this.activeTab = tab;
            if (tab === 1) {
                vm.GetLineItemHistoryReport();
            }
            if (tab === 2) {
                vm.GetInvoiceActionHistoryReport();
            }
        },
        Close() {
            this.$parent.isUsicInvoiceHistory = false;
        }
    }
};
</script>